#define fp float

#define NUMBER_PAR_PER_BOX 100
#define THREADS_PER_BOX 128

#define DOT(A,B) ((A.x)*(B.x)+(A.y)*(B.y)+(A.z)*(B.z))

typedef struct
{
    fp x, y, z;
} THREE_VECTOR;

typedef struct
{
    fp v, x, y, z;
} FOUR_VECTOR;

typedef struct nei_str
{
    int x, y, z;
    int number;
    long offset;
} nei_str;

typedef struct box_str
{
    int x, y, z;
    int number;
    long offset;
    int nn;
    nei_str nei[26];
} box_str;

typedef struct par_str
{
    fp alpha;
} par_str;

typedef struct dim_str
{
    int cur_arg;
    int arch_arg;
    int cores_arg;
    int boxes1d_arg;
    long number_boxes;
    long box_mem;
    long space_elem;
    long space_mem;
    long space_mem2;
} dim_str;

__kernel void kernel_gpu_opencl(
    par_str par,
    dim_str dim,
    __global box_str* box,
    __global FOUR_VECTOR* rv,
    __global fp* qv,
    __global FOUR_VECTOR* fv)
{
    int global_id = get_global_id(0);

    // Launch configuration: global_size = number_boxes * 128
    int box_id = global_id / THREADS_PER_BOX;
    int tid = global_id % THREADS_PER_BOX;

    if (box_id >= dim.number_boxes) return;
    if (tid >= NUMBER_PAR_PER_BOX) return;

    fp alpha = par.alpha;
    fp a2 = 2.0f * alpha * alpha;

    long first_i = box[box_id].offset;
    FOUR_VECTOR rA_local;
    FOUR_VECTOR fA_local;

    rA_local = rv[first_i + tid];
    fA_local = fv[first_i + tid];

    fp r2;
    fp u2;
    fp fs;
    fp vij;
    fp fxij, fyij, fzij;
    THREE_VECTOR d;

    for (int k = 0; k < (1 + box[box_id].nn); k++) {
        int pointer;
        if (k == 0) {
            pointer = box_id;
        } else {
            pointer = box[box_id].nei[k-1].number;
        }

        long first_j = box[pointer].offset;

        for (int j = 0; j < NUMBER_PAR_PER_BOX; j++) {
            FOUR_VECTOR rB_j = rv[first_j + j];
            fp qB_j = qv[first_j + j];

            r2 = rA_local.v + rB_j.v - DOT(rA_local, rB_j);
            u2 = a2 * r2;
            vij = exp(-u2);
            fs = 2.0f * vij;

            d.x = rA_local.x - rB_j.x;
            d.y = rA_local.y - rB_j.y;
            d.z = rA_local.z - rB_j.z;

            fxij = fs * d.x;
            fyij = fs * d.y;
            fzij = fs * d.z;

            fA_local.v += qB_j * vij;
            fA_local.x += qB_j * fxij;
            fA_local.y += qB_j * fyij;
            fA_local.z += qB_j * fzij;
        }
    }

    fv[first_i + tid] = fA_local;
}
